import os
import pymysql
from pymysql.err import OperationalError
from flask import Flask, request, jsonify

app = Flask(__name__)

connection_name = os.getenv('CONNECTION_NAME')
db_name = os.getenv('DB_NAME')
db_user = os.getenv('DB_USER')
db_password = os.getenv('DB_PASSWORD')

mysql_config = {
    'user': db_user,
    'password': db_password,
    'db': db_name,
    'charset': 'utf8mb4',
    'cursorclass': pymysql.cursors.DictCursor,
    'autocommit': True
}

# Create SQL connection globally to reuse
mysql_conn = None

def __get_cursor():
    try:
        conn = pymysql.connect(**mysql_config, unix_socket=f"/cloudsql/{connection_name}")
    except OperationalError:
        # If connection failed, return None
        conn = None
    return conn

def __get_mysql_conn():
    global mysql_conn
    # Use global variable for connection
    if mysql_conn is None:
        mysql_conn = __get_cursor()
    return mysql_conn

@app.route('/search', methods=['GET'])
def search():
    connection = __get_mysql_conn()

    # Use parameters from the URL to build a query
    query = "SELECT * FROM my_table"
    params = request.args

    if params:
        filters = []
        for key, value in params.items():
            filters.append(f"{key} LIKE '%{value}%'")

        query += " WHERE " + " AND ".join(filters)

    with connection.cursor() as cursor:
        cursor.execute(query)
        result = cursor.fetchall()
        
    return jsonify(result)

